import re

class Piece:
    def __init__(self, color):
        self.color = color

class Board:
    def __init__(self):
        self.board = [[' ' for _ in range(8)] for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        colors = ['b', 'r']
        row_indices = [0, 2, 4, 6]
        for color, row_idx in zip(colors, row_indices):
            for col_idx in range(8):
                if (row_idx + col_idx) % 2 == 1:
                    self.board[row_idx][col_idx] = Piece(color)

    def display(self):
        for row in self.board:
            print(" ".join(piece.color if piece else ' ' for piece in row))

    def is_valid_move(self, start_pos, end_pos):
        # Simple validation (no capture logic)
        start_row, start_col = start_pos
        end_row, end_col = end_pos
        return self.board[start_row][start_col] and \
               abs(start_row - end_row) == 1 and \
               abs(start_col - end_col) == 1

    def move_piece(self, start_pos, end_pos):
        start_row, start_col = start_pos
        end_row, end_col = end_pos
        piece = self.board[start_row][start_col]
        if self.is_valid_move(start_pos, end_pos):
            self.board[end_row][end_col] = piece
            self.board[start_row][start_col] = None
            return True
        return False

    def is_game_over(self):
        # Simple check (no win or draw logic)
        for row in range(8):
            for col in range(8):
                if isinstance(self.board[row][col], Piece):
                    return False
        return True

def get_user_input():
    pattern = r'^[a-h]\d-[a-h]\d$'
    while True:
        user_input = input("Enter your move (e.g., a1-b2): ")
        if re.match(pattern, user_input):
            return user_input

def main():
    board = Board()
    current_player = 'b'

    while not board.is_game_over():
        print(f"\nCurrent player: {current_player}")
        board.display()
        user_input = get_user_input()
        start_pos, end_pos = (int(user_input[1]) - 1, ord(user_input[0]) - 97), (int(user_input[4]) - 1, ord(user_input[3]) - 97)

        if board.move_piece(start_pos, end_pos):
            current_player = 'r' if current_player == 'b' else 'b'
        else:
            print("Invalid move. Please try again.")

    print("\nGame Over!")

if __name__ == "__main__":
    main()
```

